mapper.select:
SELECT id, email, last_name AS lastName, first_name AS firstName, last_name_kana AS lastNameKana, first_name_kana AS firstNameKana, phone, role, esg_point AS esgPoint, created_at AS createdAt, updated_at AS updatedAt, deleted_at AS deletedAt FROM members
AND (email LIKE CONCAT('%', #{keyword}, '%') OR last_name LIKE CONCAT('%', #{keyword}, '%') OR first_name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
AND role = #{role}
AND deleted_at IS NULL
ORDER BY created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT s.id, s.name, s.category, s.address, s.business_number AS businessNumber, s.open_time AS openTime, s.close_time AS closeTime, s.thumbnail_url AS thumbnailUrl, s.created_at AS createdAt, s.deleted_at AS deletedAt, s.stop_reason AS stopReason, m.id AS ownerId, m.email AS ownerEmail, CONCAT(m.last_name, ' ', m.first_name) AS ownerName FROM stores s JOIN members m ON s.owner_id = m.id
AND (s.name LIKE CONCAT('%', #{keyword}, '%') OR s.address LIKE CONCAT('%', #{keyword}, '%') OR m.email LIKE CONCAT('%', #{keyword}, '%'))
AND s.category = #{category}
AND s.deleted_at IS NULL
AND s.deleted_at IS NOT NULL
ORDER BY s.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT o.id, o.order_status AS orderStatus, o.total_price AS totalPrice, o.pickup_code AS pickupCode, o.created_at AS createdAt, CONCAT(m.last_name, ' ', m.first_name) AS memberName, m.email AS email, s.name AS storeName, (SELECT COUNT(*) FROM order_items oi WHERE oi.order_id = o.id) AS itemCount FROM orders o JOIN members m ON o.member_id = m.id JOIN stores s ON o.store_id = s.id
AND (m.email LIKE CONCAT('%', #{keyword}, '%') OR m.last_name LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') OR o.pickup_code LIKE CONCAT('%', #{keyword}, '%'))
AND o.order_status = #{status}
ORDER BY o.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT r.id, r.title, r.content, r.rating, r.photo_url AS photoUrl, r.created_at AS createdAt, r.deleted_at AS deletedAt, CONCAT(m.last_name, ' ', m.first_name) AS memberName, m.email AS email, s.name AS storeName FROM reviews r JOIN members m ON r.member_id = m.id JOIN stores s ON r.store_id = s.id
AND (r.title LIKE CONCAT('%', #{keyword}, '%') OR r.content LIKE CONCAT('%', #{keyword}, '%') OR m.email LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
AND r.rating <= #{maxRating}
ORDER BY r.created_at DESC LIMIT #{pageSize} OFFSET #{offset}
